import "./App.css"
import { useState, useEffect, useRef } from "react"

function randomScenario() {
  return Math.random() < 0.5 ? 0 : 1
}

export default function App() {
  const [scenario, setScenario] = useState(randomScenario())
  const [reacted, setReacted] = useState(false)
  const [points, setPoints] = useState(0)
  const [gameStarted, setGameStarted] = useState(false)
  const [message, setMessage] = useState("You should not stop there!")
  const [scenariosCompleted, setScenariosCompleted] = useState(0)
  const [difficulty, setDifficulty] = useState(0)
  const [gameOver, setGameOver] = useState(false)

  function startGame() {
    setGameStarted(true)
  }

  function handleRestart() {
    setGameStarted(false)
    setPoints(0)
    setScenariosCompleted(0)
    setGameOver(false)
  }

  function handleScoring(timeTook) {
    let newPoints = points
    switch (difficulty) {
      case 0:
        if (timeTook < 600) {
          newPoints += 100
          setMessage("Perfect!")
        }
        else if (timeTook < 800) {
          newPoints += 75
          setMessage("Great!")
        }
        else if (timeTook < 1200) {
          newPoints += 50
          setMessage("Good!")
        }
        else {
          newPoints -= 50
          setMessage("Not quick enough!")
        }
        setPoints(newPoints)
        console.log(newPoints)
        console.log(newPoints >= 300)
        if (newPoints >= 300) {
          setDifficulty(1)
          setMessage(message + " Difficulty increased!")
        }
        break;
      case 1:
        if (timeTook < 500) {
          newPoints += 100
          setMessage("Perfect!")
        }
        else if (timeTook < 700) {
          newPoints += 75
          setMessage("Great!")
        }
        else if (timeTook < 1000) {
          newPoints += 50
          setMessage("Good!")
        }
        else {
          newPoints -= 50
          setMessage("Not quick enough!")
        }
        setPoints(newPoints)
        if (newPoints >= 700) {
          setDifficulty(2)
          setMessage(message + " Difficulty increased!")
        }
        break;
      case 2:
        if (timeTook < 400) {
          newPoints += 100
          setMessage("Perfect!")
        }
        else if (timeTook < 550) {
          newPoints += 75
          setMessage("Great!")
        }
        else if (timeTook < 700) {
          newPoints += 50
          setMessage("Good!")
        }
        else {
          newPoints -= 50
          setMessage("Not quick enough!")
        }
        setPoints(newPoints)
        break;
    }

  }

  function handleReaction(shouldReact, startTime, reactionTime) {
    setReacted(true)
    setScenariosCompleted(scenariosCompleted + 1)
    if (shouldReact) {
      let timeTook = reactionTime - startTime
      handleScoring(timeTook)
      console.log(timeTook)
    }
    else {
      setPoints(points - 100)
      setMessage("You should not stop there!")
    }
  }

  function newScenario() {
    setScenario(randomScenario())
    setReacted(false)
    if (scenariosCompleted >= 10) {
      setGameOver(true)
    }
  }

  function TrafficLight() {
    const [index, setIndex] = useState(2)
    const startTime = useRef(null)

    useEffect(() => {
      const timer = setTimeout(() => {
        setIndex(1)
        startTime.current = Date.now()
      }, Math.random() * 9000 + 2000)

      return () => clearTimeout(timer)
    }, [])

    const images = [
      {
        name: "red-traffic-light",
        url: "data:image/png;base64,",
        shouldReact: true
      },
      {
        name: "yellow-traffic-light",
        url: "data:image/png;base64,",
        shouldReact: true
      },
      {
        name: "green-traffic-light",
        url: "data:image/png;base64,",
        shouldReact: false
      }
    ]

    return (
      <div className="scenarioContainer">
        <img src={images[index].url} className="scenarioImage" />
        <button className="stopButton" onClick={() => {
          handleReaction(images[index].shouldReact, startTime.current, Date.now())
        }}>
          Stop
        </button>
      </div>
    )
  }

  function Pedestrian() {
    const [index, setIndex] = useState(0)
    const startTime = useRef(null)

    useEffect(() => {
      const timer = setTimeout(() => {
        setIndex(1)
        startTime.current = Date.now()
      }, Math.random() * 10000 + 2000)

      return () => clearTimeout(timer)
    }, [])

    const images = [
      {
        name: "pedestrian-standing",
        url: "data:image/png;base64,",
        shouldReact: false
      },
      {
        name: "pedestrian-crossing",
        url: "data:image/png;base64,",
        shouldReact: true
      }
    ]

    return (
      <div className="scenarioContainer">
        <img src={images[index].url} className="scenarioImage" />
        <button className="stopButton" onClick={() => {
          handleReaction(images[index].shouldReact, startTime.current, Date.now())
        }}>
          Stop
        </button>
      </div>
    )
  }

  function Scenario() {
    if (scenario === 0)
      return <TrafficLight />
    else
      return <Pedestrian />
  }

  return (
    <main>
      <h2 id="title">Reaction Time Game</h2>
      {!gameStarted && !gameOver &&
        <div id="prestartContainer">
          <div id="description">
            You are driving a car and must react in time to stop in certain scenarios. The faster you react, the more points you get, but don't react too early! You will have less time to react as your score gets higher.
          </div>
          <button id="startButton" onClick={() => startGame()}>Start</button>
        </div>
      }
      {gameStarted && !gameOver && !reacted &&
        <Scenario />
      }
      {gameStarted && !gameOver && reacted &&
        <div id="postReactionContainer">
          <h3>{message}</h3>
          <h3>Current score: {points}</h3>
          <button style={{ backgroundColor: "#0073FF" }} onClick={() => newScenario()}>
            Next
          </button>
        </div>
      }
      {gameOver &&
        <div id="gameOverContainer">
          <h2>Game over!</h2>
          <h3>Your final score: {points}</h3>
          <button style={{ backgroundColor: "#0073FF" }} onClick={() => handleRestart()}>Start over</button>
        </div>
      }
    </main>
  )
}